  ('dietitian-moex-06977', 'dietitian', 'dietitian-moex-103-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '老人安養機構住民250人，若廚房只能選購3種基本設備，則下列那些為宜？①鼓風式瓦斯炒爐 ②電烤', '["蒸庫", "煎臺 ⑤蒸汽迴轉鍋", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "669e3f56ea31", "answer_pdf_sha1": "44b27236efc3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "團體膳食設計與管理", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 22, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-06978', 'dietitian', 'dietitian-moex-103-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '下列敘述何者錯誤？ 油煙機之抽氣能力以能排氣至少80%為原則 刀具、砧板保管箱應有紫外線殺菌設備 器具、餐具及器皿洗滌消毒設備，至少應具備三槽式洗滌設備 冷凍及冷藏設備之貯物容積宜在70%以下', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "669e3f56ea31", "answer_pdf_sha1": "44b27236efc3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "團體膳食設計與管理", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 23, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-06979', 'dietitian', 'dietitian-moex-103-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '根據「即食餐食工廠良好作業規範專則」之規定，下列敘述何者錯誤？ 原料處理場、烹調場等場所，其地面應有適當之排水斜度（應在1/100以上）及排水系統 排水溝之側面和底面接合處應有適當之弧度（曲率半徑應在3公分以上） 烹飪場內之天花板至少要離地面2.0公尺以上 管制作業區之室內窗檯，檯面深度如有2公分以上者，其檯面與水平面之夾角應達45度以上', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "669e3f56ea31", "answer_pdf_sha1": "44b27236efc3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "團體膳食設計與管理", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 24, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
