  ('dietitian-moex-06981', 'dietitian', 'dietitian-moex-103-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '績效評估方法中，常被用於評估一個具有管理潛力的工作人員或中級主管，其中包含人格、工作潛力、 人際關係，此評估技術常運用多種評估方法及多位評估人員參與，此評估方法為何？ 評核中心  排列順序  人與人比較  自我評估', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "669e3f56ea31", "answer_pdf_sha1": "44b27236efc3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "團體膳食設計與管理", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 26, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
